insert into public.security_aliases (
  id,
  security_id,
  alias_text_normalized,
  alias_source,
  confidence
)
select
  alias_data.id::uuid,
  security.id,
  alias_data.alias_text_normalized,
  alias_data.alias_source,
  alias_data.confidence::numeric
from (select id from public.securities where provider_name = 'manual_fund_nav' and provider_symbol = 'IE0032126645' limit 1) as security(id)
cross join (
values
  ('d83ce196-8a58-5f1f-8846-8022f646bd99', 'VANGUARD U.S. 500 STOCK INDEX FUND EUR ACC', 'manual', 1.0),
